function e(e,t=`https://img.ophim.live`){if(!e||typeof e!=`string`)return``;if(e.startsWith(`http://`)||e.startsWith(`https://`))return e;if(e.startsWith(`//`))return`https:${e}`;if(e.startsWith(`movies/`))return`${t}/${e}`;if(!e.includes(`/`))return`${t}/uploads/movies/${e}`;let n=e.startsWith(`/`)?e:`/${e}`;return n.startsWith(`/uploads`)||n.startsWith(`/images`),`${t}${n}`}export{e as t};